import React, { useEffect, useRef, useState } from "react";
import "./Experience.css";

const CLIENTS = [
  {
    id: 1,
    name: "Sneha Taori",
    website: "https://snehataori.com",
    websiteLabel: "snehataori.com",
    period: "Aug 2024 – Apr 2025",
    role: "Senior Video Editor",
    industry: "Content Creator",
    location: "India",
    color: "#f72585",
    colorAlt: "#7b5ea7",
    description:
      "Crafted high-retention short and long-form video content for a personal brand audience. Developed a signature visual language through precise cuts, dynamic pacing, and cinematic colour grading that drove consistent audience growth.",
    stats: [
      { value: "9 mo", label: "Collaboration" },
      { value: "50+", label: "Videos Edited" },
      { value: "↑ 3×", label: "Engagement Growth" },
    ],
    initials: "ST",
  },
  {
    id: 2,
    name: "Sanjay Arora",
    website: "https://shellsindia.com",
    websiteLabel: "shellsindia.com",
    period: "May 2025 – Present",
    role: "Senior Video Editor",
    industry: "Advertising Agency",
    location: "Nagpur, India",
    color: "#4361ee",
    colorAlt: "#738af5",
    description:
      "Producing video content for Shells Advertising Inc — one of central India's largest advertising agencies with 34+ years in the industry. Creating campaign videos, brand stories, and digital content for clients including Haldiram's, DM IMS, Spacewood, and more.",
    stats: [
      { value: "34+", label: "Yr Agency Legacy" },
      { value: "12+", label: "Brand Clients" },
      { value: "Now", label: "Active Role" },
    ],
    initials: "SA",
  },
];

function hexToRgb(hex) {
  const safeHex = (hex || "").replace("#", "");
  const fullHex =
    safeHex.length === 3
      ? safeHex
          .split("")
          .map((c) => c + c)
          .join("")
      : safeHex;
  const intVal = parseInt(fullHex, 16);
  if (Number.isNaN(intVal)) return "247,37,133";
  const r = (intVal >> 16) & 255;
  const g = (intVal >> 8) & 255;
  const b = intVal & 255;
  return `${r}, ${g}, ${b}`;
}

function parseNumericPrefix(value) {
  const match = String(value).trim().match(/^(\d+)(.*)$/);
  if (!match) return null;
  return {
    target: parseInt(match[1], 10),
    suffix: match[2] || "",
  };
}

function useCounter(target, duration, delay) {
  const [count, setCount] = useState(0);
  const timeoutRef = useRef(null);
  const intervalRef = useRef(null);

  useEffect(() => {
    setCount(0);
    timeoutRef.current = setTimeout(() => {
      const steps = Math.max(1, Math.floor(duration / 16));
      let step = 0;
      intervalRef.current = setInterval(() => {
        step += 1;
        const next = Math.min(Math.round((step / steps) * target), target);
        setCount(next);
        if (step >= steps) {
          clearInterval(intervalRef.current);
          intervalRef.current = null;
        }
      }, 16);
    }, delay);

    return () => {
      clearTimeout(timeoutRef.current);
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
      }
    };
  }, [target, duration, delay]);

  return count;
}

function StatItem({ stat, delay, accent }) {
  const parsed = parseNumericPrefix(stat.value);
  const count = useCounter(parsed ? parsed.target : 0, 1200, delay);
  const [textVisible, setTextVisible] = useState(false);
  const textTimerRef = useRef(null);

  useEffect(() => {
    if (parsed) return undefined;
    setTextVisible(false);
    textTimerRef.current = setTimeout(() => {
      setTextVisible(true);
    }, delay + 800);
    return () => {
      clearTimeout(textTimerRef.current);
    };
  }, [delay, parsed]);

  const displayValue = parsed ? `${count}${parsed.suffix}` : stat.value;

  return (
    <div className="experience-stat">
      <div
        className={`experience-stat-value ${parsed ? "is-counting" : "is-text"} ${
          textVisible ? "is-visible" : ""
        }`}
        style={{ "--accent": accent }}
      >
        {displayValue}
      </div>
      <div className="experience-stat-label">{stat.label}</div>
    </div>
  );
}

function ClientCard({ client, index }) {
  const rgb = hexToRgb(client.color);
  const cardDelay = index === 0 ? 300 : 500;

  return (
    <article
      className={`experience-card ${index === 0 ? "card-left" : "card-right"}`}
      style={{
        "--accent": client.color,
        "--accent-alt": client.colorAlt,
        "--accent-rgb": rgb,
        "--card-delay": `${cardDelay}ms`,
      }}
    >
      <span className="card-top-accent" aria-hidden="true" />
      <span className="card-ambient-glow" aria-hidden="true" />

      <div className="card-head">
        <div className="orbital-avatar" aria-hidden="true">
          <span className="orbital-outer-glow" />
          <span className="orbit-ring" />
          <span className="orbit-dot-wrap">
            <span className="orbit-dot" />
          </span>
          <span className="avatar-core">{client.initials}</span>
        </div>

        <div className="name-block">
          <h2 className="client-name">{client.name}</h2>
          <p className="client-role">{client.role}</p>
          <span className="industry-pill">
            <span className="industry-pill-dot" aria-hidden="true" />
            {client.industry}
          </span>
        </div>
      </div>

      <div className="period-pill">
        <svg viewBox="0 0 16 16" width="12" height="12" aria-hidden="true">
          <rect x="1" y="3" width="14" height="12" rx="2" />
          <path d="M1 7h14M5 1v4M11 1v4" />
        </svg>
        <span>{client.period}</span>
      </div>

      <p className="card-description">{client.description}</p>

      <div className="stats-row">
        {client.stats.map((stat, statIndex) => (
          <StatItem
            key={stat.label}
            stat={stat}
            delay={cardDelay + 220 + statIndex * 90}
            accent={client.color}
          />
        ))}
      </div>

      <a
        className="website-link"
        href={client.website}
        target="_blank"
        rel="noreferrer"
      >
        <span>{client.websiteLabel}</span>
        <svg viewBox="0 0 10 10" width="10" height="10" aria-hidden="true">
          <path d="M1 9L9 1M9 1H3M9 1v6" />
        </svg>
      </a>
    </article>
  );
}

export default function Experience() {
  return (
    <section className="experience-page">
      <div className="experience-shell">
        <h1 className="experience-heading">Experience</h1>

        <div className="experience-cards-row">
          {CLIENTS.map((client, index) => (
            <ClientCard key={client.id} client={client} index={index} />
          ))}
        </div>

        <p className="experience-context-line">
          Nagpur, India · 2024 – Present · Open to new collaborations
        </p>
      </div>
    </section>
  );
}
